/**
 * Componente CarSprite - Renderiza o sprite do carro
 * Commit: Implementação do componente de sprite com rotação dinâmica
 */

import React, { useMemo } from 'react';
import { calculateSpriteFrame, getSpritePositionX, getSpriteDimensions } from '../../utils/spriteCalculator';
import './CarSprite.scss';

const CarSprite = ({ 
  direction = 0, 
  speed = 0, 
  color = '#FFEB3B',
  size = 'medium'
}) => {
  const frameIndex = useMemo(() => calculateSpriteFrame(direction), [direction]);
  const positionX = useMemo(() => getSpritePositionX(frameIndex), [frameIndex]);
  const dimensions = useMemo(() => getSpriteDimensions(), []);

  const sizeClass = useMemo(() => {
    const sizes = {
      small: 'car-sprite--small',
      medium: 'car-sprite--medium',
      large: 'car-sprite--large'
    };
    return sizes[size] || sizes.medium;
  }, [size]);

  const spriteStyle = {
    backgroundImage: `url(${process.env.PUBLIC_URL}/sprites/car-sprite.png)`,
    backgroundPosition: `-${positionX}px 0`,
    backgroundSize: `${dimensions.totalWidth}px ${dimensions.height}px`,
    width: `${dimensions.width}px`,
    height: `${dimensions.height}px`,
  };

  return (
    <div 
      className={`car-sprite ${sizeClass}`}
      style={spriteStyle}
      data-direction={direction.toFixed(1)}
      data-speed={speed.toFixed(1)}
      data-frame={frameIndex}
    >
      <div 
        className="car-sprite__indicator"
        style={{ backgroundColor: color }}
      />
    </div>
  );
};

export default CarSprite;
